#!/usr/bin/env python3
"""
Palm Beach Diva — About Section Photo Swap
Usage: python3 swap_photos.py index.html > new_index.html
Then: mv new_index.html index.html  then push to GitHub
"""
import re, sys

if len(sys.argv) < 2:
    print("Usage: python3 swap_photos.py index.html > new_index.html")
    sys.exit(1)

with open(sys.argv[1], 'r', encoding='utf-8') as f:
    html = f.read()

MILAN_B64 = ""
PALM_BEACH_B64 = ""
MONTE_CARLO_B64 = ""

NEW_MAIN = (
    '<div class="lucie-main-photo">\n'
    '        <img src="data:image/jpeg;base64,' + MILAN_B64 + '" '
    'alt="Lucie Burdova — Milan" loading="lazy">\n'
    '        <div class="photo-location-tag">Milan</div>\n'
    '      </div>'
)

NEW_TOP = (
    '<div class="lucie-side-photo lucie-side-photo--top">\n'
    '          <img src="data:image/jpeg;base64,' + PALM_BEACH_B64 + '" '
    'alt="Lucie Burdova — Palm Beach" loading="lazy">\n'
    '          <div class="photo-location-tag">Palm Beach</div>\n'
    '        </div>'
)

NEW_BOTTOM = (
    '<div class="lucie-side-photo lucie-side-photo--bottom">\n'
    '          <img src="data:image/jpeg;base64,' + MONTE_CARLO_B64 + '" '
    'alt="Lucie Burdova — Monte Carlo" loading="lazy">\n'
    '          <div class="photo-location-tag">Monte Carlo</div>\n'
    '        </div>'
)

html = re.sub(
    r'<div class="lucie-main-photo">[\s\S]*?<div class="photo-location-tag">[^<]*</div>\s*\n\s*</div>',
    NEW_MAIN, html, count=1
)
html = re.sub(
    r'<div class="lucie-side-photo lucie-side-photo--top">[\s\S]*?<div class="photo-location-tag">[^<]*</div>\s*\n\s*</div>',
    NEW_TOP, html, count=1
)
html = re.sub(
    r'<div class="lucie-side-photo lucie-side-photo--bottom">[\s\S]*?<div class="photo-location-tag">[^<]*</div>\s*\n\s*</div>',
    NEW_BOTTOM, html, count=1
)

sys.stdout.write(html)
print("Done! Photo swap complete.", file=sys.stderr)
